import styled from "styled-components";

export const Card = styled.div`
    width: 30%;
`;

export const Picture = styled.img`
    width: 80%;
    height: calc(100vh - 600px);
    border-radius: 50%;
`;

export const TitleProduto = styled.h3`
    font-size: 1.5em;
`;

export const DescProduto = styled.p`
`;
